    
    
    
   
    import init, { CoreEngine } from './pkg/wasm_security.js';
    

    const audio = document.getElementById('mainAudio');
    const playlistElem = document.getElementById('playlist');
    const coverImg = document.getElementById('coverImg');
    const currentTitle = document.getElementById('currentTitle');
    const currentArtist = document.getElementById('currentArtist');
    const searchInput = document.getElementById('search');
    const countLabel = document.getElementById('count');
    const canvas = document.getElementById('visualizer');
    const ctx = canvas.getContext('2d');
    const playerNode = document.getElementById('playerNode');
    const DEFAULT_COVER = "data:image/jpeg;base64,";
    ddd.src="data:image/png;base64,";
    coverImg.src = DEFAULT_COVER;
   
    let allSongs = [];
    let analyser, dataArray, bufferLength;
    let audioCtx;

    let lastDrawTime = 0;
    const VISUALIZER_FPS = 40;
    const FRAME_INTERVAL = 1000 / VISUALIZER_FPS;
    const AMPLITUDE_SCALE = 15;
    
    let engine;
    async function fetchSongs() {
        
            await init();
            engine = new CoreEngine();
            
            
            allSongs = await engine.fetch_and_process_playlist();
        
        
            if (allSongs) {
                renderList(allSongs);
            }
            countLabel.innerText =allSongs.length;
            
          
        
    }

    function renderList(songs) {
        playlistElem.innerHTML = '';
        songs.forEach((path, index) => {
            const fileName = path.name;
            const div = document.createElement('div');
            div.className = 'audio-item';
            div.innerHTML = `<span>${fileName}</span>`;
            div.onclick = () => playSong(path, div);
            playlistElem.appendChild(div);
        });
    }

    async function playSong(path, element) {
        document.querySelectorAll('.audio-item').forEach(el => el.classList.remove('active'));
        element.classList.add('active');
        
        const fileName = path.name;
        currentTitle.innerText = fileName;
        audio.crossOrigin = "anonymous";
        audio.src = path.path;

        coverImg.src = DEFAULT_COVER;
        currentArtist.innerText = "加载中...";

        try {
            await audio.play();
            playerNode.classList.add('playing');
            initVisualizer();
        } catch (e) {
            console.log("播放失败:", e);
        }

        try {
            const res = await fetch(path.path);
            const blob = await res.blob();
            jsmediatags.read(blob, {
                onSuccess: function(tag) {
                    const tags = tag.tags || {};
          
                    if (tags.picture) {
                        const { data, format } = tags.picture;
                      
                        const uint8Array = new Uint8Array(data);
       
                        const blob = new Blob([uint8Array], { type: format });

                        coverImg.src = URL.createObjectURL(blob);
                    }
                   
                    currentArtist.innerText = tags.artist || tags.album || "拉丝吉他堡";
                },
                onError: function() {
                    currentArtist.innerText = "拉丝吉他堡";
                }
            });
        } catch (e) {
            
            currentArtist.innerText = "拉丝吉他堡";
        }
    }

    function initVisualizer() {
        if (audioCtx) {
            audioCtx.resume();
            canvas.width = canvas.offsetWidth;
            canvas.height = canvas.offsetHeight;
            return;
        }
        canvas.width = canvas.offsetWidth;
        canvas.height = canvas.offsetHeight;

        audioCtx = new (window.AudioContext || window.webkitAudioContext)();
        analyser = audioCtx.createAnalyser();
        const source = audioCtx.createMediaElementSource(audio);
        source.connect(analyser);
        analyser.connect(audioCtx.destination);
        analyser.fftSize = 512;
        bufferLength = analyser.frequencyBinCount;
        dataArray = new Uint8Array(bufferLength);
        draw();
    }

    function draw() {
        // 1. 循环调用自身
        requestAnimationFrame(draw);
        
        const now = Date.now();
        const elapsedTime = now - lastDrawTime;
        if (elapsedTime < FRAME_INTERVAL) return;
        lastDrawTime = now;

        analyser.getByteFrequencyData(dataArray);

    
        const drawData = engine.get_symmetric_spectrum(dataArray);
        if (!drawData || drawData.length === 0) {
            console.info("???");
            return;
        } 
        const raw = engine.compute_bars(drawData, canvas.width, canvas.height);

        const barCount = raw.length / 5;

        ctx.clearRect(0, 0, canvas.width, canvas.height);

        for (let i = 0; i < barCount; i++) {
            const idx = i * 5;

            const x = raw[idx];
            const y = raw[idx + 1];
            const width = raw[idx + 2];
            const height = raw[idx + 3];
            const hue = raw[idx + 4];

            const gradient = ctx.createLinearGradient(0, y, 0, canvas.height);
            gradient.addColorStop(0, 'rgba(210, 230, 255, 0.8)');
            gradient.addColorStop(0.8, 'rgba(100, 150, 255, 0.4)');
            gradient.addColorStop(1, 'rgba(30, 60, 150, 0.0)');

            ctx.shadowBlur = 10;
            ctx.shadowColor = `hsla(${hue}, 100%, 70%, 0.5)`;

            ctx.fillStyle = gradient;
            ctx.fillRect(x, y, width, height);

            ctx.fillStyle = "#FFFFFF";
            ctx.shadowBlur = 15;
            ctx.shadowColor = "#FFFFFF";
            ctx.fillRect(x, y, width, 2);
        }

        ctx.shadowBlur = 0;
    }

    searchInput.oninput = () => {
        const val = searchInput.value.toLowerCase();
        const filtered = allSongs.filter(song => {
            return song.name.toLowerCase().includes(val);
        });
        renderList(filtered);
    };

    audio.addEventListener('pause', () => {
        playerNode.classList.remove('playing');
    });
    audio.addEventListener('play', () => {
        playerNode.classList.add('playing');
    });
    audio.addEventListener('ended', () => {
        playerNode.classList.remove('playing');
    });

    window.addEventListener('resize', () => {
        if(canvas.offsetWidth !== canvas.width || canvas.offsetHeight !== canvas.height){
            canvas.width = canvas.offsetWidth;
            canvas.height = canvas.offsetHeight;
        }
    });

    window.onload = fetchSongs();
